<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***DatabaseConnectionManager-SingletonPattern*PartofMVCArchitecture*/classDatabase{privatestatic$instance=null;private$pdo;privatefunction__construct(){try{/Trysocketfirst(XAMPP),thenfallbacktoTCP$dsn="mysql:host=".DB_HOST.";dbname=".DB_NAME.";unix_socket=/opt/lampp/var/mysql/mysql.sock";try{$this->pdo=newPDO($dsn,DB_USER,DB_PASS);}catch(PDOException$e){/FallbacktoTCPconnection$dsn="mysql:host=".DB_HOST.";dbname=".DB_NAME;$this->pdo=newPDO($dsn,DB_USER,DB_PASS);}$this->pdo->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$this->pdo->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);$this->pdo->setAttribute(PDO::ATTR_EMULATE_PREPARES,false);/Settimezone$this->pdo->exec("SETtime_zone='+07:00'");$this->pdo->exec("SETSESSIONsql_mode='STRICT_ALL_TABLES'");}catch(PDOException$e){error_log("Databaseconnectionfailed:".$e->getMessage());thrownewException("Databaseconnectionfailed");}}/***Getsingletoninstance*/publicstaticfunctiongetInstance(){if(self::$instance===null){self::$instance=newself();}returnself::$instance;}/***GetPDOconnection*/publicfunctiongetConnection(){return$this->pdo;}/***Executequerywithparameters*/publicfunctionquery($sql,$params=[]){$stmt=$this->pdo->prepare($sql);$stmt->execute($params);return$stmt;}/***Fetchallresults*/publicfunctionfetchAll($sql,$params=[]){return$this->query($sql,$params)->fetchAll();}/***Fetchsinglerow*/publicfunctionfetchOne($sql,$params=[]){return$this->query($sql,$params)->fetch();}/***InsertdataandreturnID*/publicfunctioninsert($table,$data){$columns=implode(',',array_keys($data));$placeholders=':'.implode(',:',array_keys($data));$sql="INSERTINTO$table($columns)VALUES($placeholders)";$this->query($sql,$data);return$this->pdo->lastInsertId();}/***Updatedata*/publicfunctionupdate($table,$data,$where,$whereParams){$setParts=[];forforeach($dataas$key=>$value){$setParts[]="$key=:$key";}$setClause=implode(',',$setParts);$sql="UPDATE$tableSET$setClauseWHERE$where";$params=array_merge($data,$whereParams);$stmt=$this->query($sql,$params);return$stmt->rowCount();}/***Deletedata*/publicfunctiondelete($table,$where,$params){$sql="DELETEFROM$tableWHERE$where";$stmt=$this->query($sql,$params);return$stmt->rowCount();}/***Softdelete(updateis_deletedflag)*/publicfunctionsoftDelete($table,$where,$params){$sql="UPDATE$tableSETis_deleted=true,updated_at=NOW()WHERE$where";$stmt=$this->query($sql,$params);return$stmt->rowCount();}/***Begintransaction*/publicfunctionbeginTransaction(){return$this->pdo->beginTransaction();}/***Committransaction*/publicfunctioncommit(){return$this->pdo->commit();}/***Rollbacktransaction*/publicfunctionrollback(){return$this->pdo->rollback();}/***GetlastinsertID*/publicfunctionlastInsertId(){return$this->pdo->lastInsertId();}/Preventcloningandunserializationprivatefunction__clone(){}publicfunction__wakeup(){thrownewException("Cannotunserializesingleton");}}?>
